import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import api from '../api';

const ProductCard = ({ product, onRefresh }) => {
  const navigate = useNavigate();
  const currentUserId = Number(localStorage.getItem('userId'));
  const isOwner = currentUserId === product.sellerId;

  const handleDelete = async () => {
    if (!window.confirm('Delete this product?')) return;
    try {
      await api.delete(`products/${product.id}`);
      if (onRefresh) onRefresh();
      else window.location.reload();
    } catch (err) {
      alert(err.response?.data?.message || 'Could not delete product');
    }
  };

  const handleBuy = async () => {
    try {
      await api.post(`products/${product.id}/buy`);
      alert('Purchase successful. The product has been marked as sold.');
      if (onRefresh) onRefresh();
      else window.location.reload();
    } catch (err) {
      alert(err.response?.data?.message || 'Could not buy product');
    }
  };

  const handleContactSeller = () => {
    navigate(`/chat?user=${product.sellerId}`);
  };

  return (
    <div style={{ border: '1px solid #ccc', borderRadius: '8px', padding: '10px', width: '240px' }}>
      {product.imagePath && <img src={`http://localhost:8080${product.imagePath}`} alt={product.title} style={{ width: '100%', height: '160px', objectFit: 'cover' }} />}
      <h3>{product.title}</h3>
      <p>₹{product.price}</p>
      <p>{product.category}</p>
      <p>{product.sold ? 'Status: Sold' : 'Status: Available'}</p>
      <Link to={`/product/${product.id}`}>View</Link>
      <div style={{ marginTop: '8px', display: 'flex', gap: '6px', flexWrap: 'wrap' }}>
        {isOwner ? (
          <>
            <Link to={`/edit/${product.id}`}><button>Edit</button></Link>
            <button onClick={handleDelete}>Delete</button>
          </>
        ) : (
          !product.sold && (
            <>
              <button onClick={handleBuy}>Buy</button>
              <button onClick={handleContactSeller}>Contact Seller</button>
            </>
          )
        )}
      </div>
    </div>
  );
};

export default ProductCard;
